index abda2a305c..338511a86a 100644
--- a/ext/date/php_date.c
+++ b/ext/date/php_date.c
@@ -2278,7 +2278,14 @@ static void update_errors_warnings(timelib_error_container **last_errors) /* {{{
 		DATEG(last_errors) = *last_errors;
 	}

-	timelib_error_container_dtor(*last_errors);
+	if ((*last_errors)->warning_count || (*last_errors)->error_count) {
+		/* Ownership transferred to DATEG(last_errors), don't destroy */
+	} else {
+		/* Only destroy if not transferring ownership to DATEG */
+	if (!((*last_errors)->warning_count || (*last_errors)->error_count)) {
+		timelib_error_container_dtor(*last_errors);
+	}
+	}
 	*last_errors = NULL;
 } /* }}} */

